<template>
    <div style="width: 40%; margin-left: 200px">
        <div style="margin-bottom: 30px; margin-left: 260px" >新增分类</div>
        <el-form :inline="true" :rules="rules" ref="ruleForm" :model="form" label-width="200px">
            <el-form-item label="名称" prop="name">
                <el-input v-model="form.name" placeholder="请输入名称"></el-input>
            </el-form-item>
            <el-form-item label="备注" prop="remark">
                <el-input v-model="form.remark" placeholder="请输入备注"></el-input>
            </el-form-item>
        </el-form>
        <div style="text-align: center; margin-top: 30px; margin-left: 10px">
            <el-button type="primary" @click="save">提交</el-button>
            <el-button style="background-color: #f3d19e; color: white" @click="change">返回</el-button>
<!--            <el-button type="danger ">取消</el-button>-->
        </div>
    </div>
</template>

<script>
    import request from "@/utils/request";
    //导入请求
    export default {
        name: "AddCategory",
        data(){
           return {
               form: {

               },
               rules: {
                   name: [
                       {required: true, message: '请输入分类名称', trigger: 'blur'},
                   ],
               }
           }

        },
        methods: {
            save() {
                this.$refs['ruleForm'].validate((valid) => {
                    if(valid){
                        request.post('/category/save',this.form).then(res =>{
                            if(res.code === '200'){
                                this.$notify.success('添加成功')
                                this.$refs['ruleForm'].resetFields();
                                this.$router.push('categoryList')
                            }else{
                                this.$notify.error(res.msg)
                            }
                        })
                    }
                })

            //    对接的是后台的UserController.java文件的路径
            },
            change() {
                this.$router.push('categoryList')
            }
        }
    }
</script>

